import { defineApp } from "rwsdk/worker";
import { route } from "rwsdk/router";

let comments: Array<{ id: number; author: string; text: string }> = [];
let nextId = 1;

// Helper to generate 32 hex chars
function generateToken() {
  const bytes = new Uint8Array(16);
  crypto.getRandomValues(bytes);
  return Array.from(bytes).map(b => b.toString(16).padStart(2, '0')).join('');
}

// Global CSRF Middleware
const csrfMiddleware = async (requestInfo: any) => {
  const { request } = requestInfo;
  const method = request.method.toUpperCase();

  if (['POST', 'PUT', 'DELETE', 'PATCH'].includes(method)) {
    const cookieHeader = request.headers.get('Cookie') || '';
    const match = cookieHeader.match(/(?:^|;\s*)csrf=([^;]+)/);
    const cookieToken = match ? match[1] : null;

    if (!cookieToken) {
      return Response.json({ error: "invalid_csrf_token" }, { status: 403 });
    }

    let submittedToken = request.headers.get('X-CSRF-Token');

    if (!submittedToken && request.headers.get('Content-Type') === 'application/x-www-form-urlencoded') {
      try {
        // Clone request to read body, but wait - if we read the body here, the route handler won't be able to read it!
        // We can clone it.
        const cloned = request.clone();
        const formData = await cloned.formData();
        submittedToken = formData.get('_csrf');
      } catch (e) {
        // ignore
      }
    }

    if (!submittedToken || submittedToken !== cookieToken) {
      return Response.json({ error: "invalid_csrf_token" }, { status: 403 });
    }
  }
};

export default defineApp([
  csrfMiddleware,

  route("/csrf", {
    get: () => {
      const token = generateToken();
      return new Response(JSON.stringify({ token }), {
        status: 200,
        headers: {
          'Content-Type': 'application/json',
          'Set-Cookie': `csrf=${token}; SameSite=Strict; Path=/`
        }
      });
    }
  }),

  route("/api/health", {
    get: () => Response.json({ status: "ok" })
  }),

  route("/api/comments", {
    get: () => Response.json(comments),
    post: async ({ request }: any) => {
      let author = '';
      let text = '';

      const contentType = request.headers.get('Content-Type') || '';
      if (contentType.includes('application/json')) {
        const body = await request.json();
        author = body.author;
        text = body.text;
      } else if (contentType.includes('application/x-www-form-urlencoded')) {
        const formData = await request.formData();
        author = formData.get('author') || '';
        text = formData.get('text') || '';
      }

      const comment = { id: nextId++, author, text };
      comments.push(comment);

      return new Response(JSON.stringify(comment), {
        status: 201,
        headers: {
          'Content-Type': 'application/json'
        }
      });
    }
  })
]);

